/**
 * search.js — lightweight client-side search powered by searchindex.json.
 *
 * Fetches the JSON search index generated by Hugo's SearchIndex output format,
 * then filters pages by the user's query across title, description, tags,
 * categories, and content.
 *
 * Mark-up contract (repeat as many times as needed, e.g. desktop + mobile):
 *
 *   <div data-search-widget>
 *     <form data-search-form data-index="/path/to/searchindex.json" role="search">
 *       <input data-search-input type="search" placeholder="Search…"
 *              aria-label="Search site content">
 *     </form>
 *     <div data-search-results aria-live="polite" aria-atomic="true"></div>
 *   </div>
 *
 * Multiple widgets on the same page share a single cached index fetch.
 */

(function () {
  "use strict";

  /** Per-URL cache: url → Promise<Array> */
  const cache = Object.create(null);

  /** Fetch and cache the search index for a given URL. */
  function loadIndex(url) {
    if (!cache[url]) {
      cache[url] = fetch(url)
        .then((res) => {
          if (!res.ok) throw new Error(`HTTP ${res.status}`);
          return res.json();
        })
        .catch((err) => {
          console.warn("[search] Could not load search index:", err);
          return [];
        });
    }
    return cache[url];
  }

  /**
   * Return pages whose text matches every whitespace-separated term in query.
   */
  function search(pages, query, maxResults = 20) {
    if (!query || !query.trim()) return [];
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    return pages
      .filter((page) => {
        const haystack = [
          page.title,
          page.description,
          (page.tags ?? []).join(" "),
          (page.categories ?? []).join(" "),
          page.content,
        ]
          .join(" ")
          .toLowerCase();
        return terms.every((term) => haystack.includes(term));
      })
      .slice(0, maxResults);
  }

  /** Minimal HTML-escape to prevent XSS in rendered results. */
  function escapeHtml(str) {
    return String(str)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  function renderResults(results, query) {
    if (!results.length) {
      return `<p class="text-sm text-gray-600 dark:text-gray-400">No results found for <strong>${escapeHtml(query)}</strong>.</p>`;
    }

    const items = results
      .map(
        (page) => `
      <article class="py-4 border-b border-gray-200 dark:border-gray-700">
        <a href="${escapeHtml(page.url)}"
           class="text-blue-600 dark:text-blue-400 font-semibold hover:underline focus:outline-none focus:ring-2 focus:ring-blue-500 rounded">
          ${escapeHtml(page.title)}
        </a>
        ${page.description ? `<p class="mt-1 text-sm text-gray-600 dark:text-gray-400">${escapeHtml(page.description)}</p>` : ""}
      </article>`
      )
      .join("");

    return `<p class="text-sm text-gray-500 dark:text-gray-400 mb-4">${results.length} result${results.length === 1 ? "" : "s"} for <strong>${escapeHtml(query)}</strong></p>
    <div role="list">${items}</div>`;
  }

  /** Wire up a single [data-search-widget] container. */
  function initSearchWidget(widget) {
    const form = widget.querySelector("[data-search-form]");
    const input = widget.querySelector("[data-search-input]");
    const resultsEl = widget.querySelector("[data-search-results]");
    if (!form || !input || !resultsEl) return;

    const url = form.dataset.index;
    if (!url) {
      console.warn("[search] data-search-form is missing a data-index attribute.");
      return;
    }

    // Pre-warm the cache so the first keystroke is fast
    loadIndex(url);

    let debounceTimer;

    input.addEventListener("input", () => {
      clearTimeout(debounceTimer);
      debounceTimer = setTimeout(async () => {
        const query = input.value.trim();
        if (!query) {
          resultsEl.innerHTML = "";
          return;
        }
        const pages = await loadIndex(url);
        resultsEl.innerHTML = renderResults(search(pages, query), query);
      }, 250);
    });

    form.addEventListener("submit", (e) => e.preventDefault());
  }

  function init() {
    document.querySelectorAll("[data-search-widget]").forEach(initSearchWidget);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
